import pytest
from urllib.parse import urlparse, urlunparse

def urldefragauth(url):
    scheme, netloc, path, params, query, fragment = urlparse(url)
    if not netloc:
        netloc, path = path, netloc
    netloc = netloc.rsplit("@", 1)[-1]
    return urlunparse((scheme, netloc, path, params, query, ""))

def test_normal_cases():
    assert urldefragauth("http://user:pass@www.example.com/path?query#fragment") == "http://www.example.com/path?query"
    assert urldefragauth("https://www.example.com/path#fragment") == "https://www.example.com/path"
    assert urldefragauth("ftp://user:pass@ftp.example.com/file.txt#fragment") == "ftp://ftp.example.com/file.txt"
    assert urldefragauth("http://www.example.com/path/to/resource#") == "http://www.example.com/path/to/resource"
    assert urldefragauth("http://www.example.com/#fragment") == "http://www.example.com/"

def test_edge_cases():
    assert urldefragauth("http://www.example.com") == "http://www.example.com"
    assert urldefragauth("http://user@www.example.com") == "http://www.example.com"
    assert urldefragauth("http://www.example.com#") == "http://www.example.com/"
    assert urldefragauth("http://www.example.com/path#fragment") == "http://www.example.com/path"
    assert urldefragauth("http://user:pass@www.example.com/path?query") == "http://www.example.com/path?query"

def test_no_scheme():
    assert urldefragauth("www.example.com/path#fragment") == "www.example.com/path"

def test_empty_url():
    assert urldefragauth("") == ""

def test_invalid_url():
    with pytest.raises(ValueError):
        urldefragauth("invalid-url")

def test_url_with_no_authentication():
    assert urldefragauth("http://www.example.com/path/to/resource#fragment") == "http://www.example.com/path/to/resource"

def test_url_with_only_fragment():
    assert urldefragauth("http://www.example.com#fragment") == "http://www.example.com/"

def test_url_with_empty_fragment():
    assert urldefragauth("http://www.example.com/path#") == "http://www.example.com/path"

def test_url_with_multiple_authentication_parts():
    assert urldefragauth("http://user:pass@user2:pass2@www.example.com/path#fragment") == "http://www.example.com/path"

def test_url_with_special_characters():
    assert urldefragauth("http://user:pass@www.example.com/path/to/resource?query=1#fragment") == "http://www.example.com/path/to/resource?query=1"

