import pytest
from unittest.mock import Mock, Callable

class HookManager:
    def __init__(self):
        self.hooks = {}

    def register_hook(self, event, hook):
        """Properly register a hook."""
        if event not in self.hooks:
            raise ValueError(f'Unsupported event specified, with event name "{event}"')

        if isinstance(hook, Callable):
            self.hooks[event].append(hook)
        elif hasattr(hook, "__iter__"):
            self.hooks[event].extend(h for h in hook if isinstance(h, Callable))

@pytest.fixture
def hook_manager():
    manager = HookManager()
    manager.hooks = {
        'event1': [],
        'event2': []
    }
    return manager

def test_register_single_callable(hook_manager):
    hook = Mock()
    hook_manager.register_hook('event1', hook)
    assert hook_manager.hooks['event1'] == [hook]

def test_register_multiple_callables(hook_manager):
    hook1 = Mock()
    hook2 = Mock()
    hook_manager.register_hook('event1', [hook1, hook2])
    assert hook_manager.hooks['event1'] == [hook1, hook2]

def test_register_iterable_with_non_callable(hook_manager):
    hook1 = Mock()
    hook2 = "not_a_callable"
    hook_manager.register_hook('event1', [hook1, hook2])
    assert hook_manager.hooks['event1'] == [hook1]

def test_register_hook_to_unsupported_event(hook_manager):
    with pytest.raises(ValueError, match='Unsupported event specified'):
        hook_manager.register_hook('unsupported_event', Mock())

def test_register_hook_to_empty_event_list(hook_manager):
    hook_manager.hooks['event3'] = []
    hook = Mock()
    hook_manager.register_hook('event3', hook)
    assert hook_manager.hooks['event3'] == [hook]

def test_register_hook_with_empty_iterable(hook_manager):
    hook_manager.register_hook('event1', [])
    assert hook_manager.hooks['event1'] == []

def test_register_hook_with_none(hook_manager):
    with pytest.raises(TypeError):
        hook_manager.register_hook('event1', None)

def test_register_hook_with_non_iterable(hook_manager):
    with pytest.raises(TypeError):
        hook_manager.register_hook('event1', 123)

def test_register_hook_to_multiple_events(hook_manager):
    hook1 = Mock()
    hook2 = Mock()
    hook_manager.register_hook('event1', hook1)
    hook_manager.register_hook('event2', hook2)
    assert hook_manager.hooks['event1'] == [hook1]
    assert hook_manager.hooks['event2'] == [hook2]

