    assert parse_header_links('<http://example.com/front.jpeg>; rel=front; type="image/jpeg", <http://example.com/back.jpeg>; rel=back; type="image/jpeg"') == [
        {'url': 'http://example.com/front.jpeg', 'rel': 'front', 'type': 'image/jpeg'},
        {'url': 'http://example.com/back.jpeg', 'rel': 'back', 'type': 'image/jpeg'}
    ]

    assert parse_header_links('<http://example.com/image.png>; rel=alternate') == [
        {'url': 'http://example.com/image.png', 'rel': 'alternate'}
    ]

    assert parse_header_links('<http://example.com/image.jpg>; rel=front; type="image/jpeg", <http://example.com/image2.jpg>; rel=back') == [
        {'url': 'http://example.com/image.jpg', 'rel': 'front', 'type': 'image/jpeg'},
        {'url': 'http://example.com/image2.jpg', 'rel': 'back'}
    ]

def test_parse_header_links_edge_cases():
    assert parse_header_links('') == []
    assert parse_header_links('   ') == []
    assert parse_header_links('<http://example.com/image.jpg>') == [
        {'url': 'http://example.com/image.jpg'}
    ]
    assert parse_header_links('<http://example.com/image.jpg>;') == [
        {'url': 'http://example.com/image.jpg'}
    ]
    assert parse_header_links('<http://example.com/image.jpg>; rel=front;') == [
        {'url': 'http://example.com/image.jpg', 'rel': 'front'}
    ]

