    assert parse_header_links('<http://example.com/image.jpg>; rel=front; type') == [
        {'url': 'http://example.com/image.jpg', 'rel': 'front'}
    ]
    assert parse_header_links('<http://example.com/image.jpg>; rel=front; type="image/jpeg"; invalid_param') == [
        {'url': 'http://example.com/image.jpg', 'rel': 'front', 'type': 'image/jpeg'}
