    assert parse_header_links('<http://example.com/image.jpg>; rel=front; type="image/jpeg", <http://example.com/image2.jpg>; invalid_param') == [
        {'url': 'http://example.com/image.jpg', 'rel': 'front', 'type': 'image/jpeg'},
        {'url': 'http://example.com/image2.jpg'}
    ]

