    assert parse_header_links('<http://example.com/image.jpg>; rel="front"; type="image/jpeg"') == [
        {'url': 'http://example.com/image.jpg', 'rel': 'front', 'type': 'image/jpeg'}
    ]
    assert parse_header_links('<http://example.com/image.jpg>; rel=front; type="image/jpeg"; charset="utf-8"') == [
        {'url': 'http://example.com/image.jpg', 'rel': 'front', 'type': 'image/jpeg', 'charset': 'utf-8'}
    ]

