import pytest

class MockResponse:
    def __init__(self, status_code, raw, content_consumed=False):
        self.status_code = status_code
        self.raw = raw
        self._content = False
        self._content_consumed = content_consumed

    def iter_content(self, chunk_size):
        return [b"chunk1", b"chunk2"]  # Mocked content

    def content(self):
        if self._content is False:
            if self._content_consumed:
                raise RuntimeError("The content for this response was already consumed")

            if self.status_code == 0 or self.raw is None:
                self._content = None
            else:
                self._content = b"".join(self.iter_content(1024)) or b""

        self._content_consumed = True
        return self._content


def test_content_normal_case():
    response = MockResponse(status_code=200, raw=b"data")
    assert response.content() == b"chunk1chunk2"


def test_content_empty_response():
    response = MockResponse(status_code=200, raw=b"data")
    response.iter_content = lambda chunk_size: []
    assert response.content() == b""


def test_content_status_code_zero():
    response = MockResponse(status_code=0, raw=b"data")
    assert response.content() is None


def test_content_raw_is_none():
    response = MockResponse(status_code=200, raw=None)
    assert response.content() is None


def test_content_already_consumed():
    response = MockResponse(status_code=200, raw=b"data", content_consumed=True)
    with pytest.raises(RuntimeError, match="The content for this response was already consumed"):
        response.content()


def test_content_multiple_calls():
    response = MockResponse(status_code=200, raw=b"data")
    assert response.content() == b"chunk1chunk2"
    assert response.content() == b"chunk1chunk2"  # Should not change on second call


def test_content_with_different_chunk_sizes():
    response = MockResponse(status_code=200, raw=b"data")
    response.iter_content = lambda chunk_size: [b"chunk1", b"chunk2"] if chunk_size == 1024 else [b"chunk3"]
    assert response.content() == b"chunk1chunk2"
    response._content_consumed = False  # Reset for next test
    assert response.content() == b"chunk1chunk2"  # Should still return the same content


def test_content_with_no_iter_content():
    response = MockResponse(status_code=200, raw=b"data")
    response.iter_content = lambda chunk_size: None
    assert response.content() == b""

