def test_content_multiple_calls():
    response = MockResponse(status_code=200, raw=b"data")
    assert response.content() == b"chunk1chunk2"
    assert response.content() == b"chunk1chunk2"  # Should not change on second call


def test_content_with_different_chunk_sizes():
    response = MockResponse(status_code=200, raw=b"data")
    response.iter_content = lambda chunk_size: [b"chunk1", b"chunk2"] if chunk_size == 1024 else [b"chunk3"]
    assert response.content() == b"chunk1chunk2"
    response._content_consumed = False  # Reset for next test
    assert response.content() == b"chunk1chunk2"  # Should still return the same content


def test_content_with_no_iter_content():
    response = MockResponse(status_code=200, raw=b"data")
    response.iter_content = lambda chunk_size: None
