    response = MockResponse(b'Hello, world!', encoding='invalid-encoding')
    assert response.text() == 'Hello, world!'

def test_text_type_error_on_encoding():
    response = MockResponse(b'Hello, world!', encoding=None)
    response.apparent_encoding = None
    assert response.text() == 'Hello, world!'

def test_text_lookup_error_on_encoding():
    response = MockResponse(b'Hello, world!', encoding='utf-16')
    assert response.text() == 'Hello, world!'

def test_text_with_replacement_characters():
    response = MockResponse(b'\xff\xfeH\x00e\x00l\x00l\x00o\x00', encoding='utf-16')
