import pytest

class TestOrdinalNumber:
    def test_ordinal_number_one(self):
        assert _ordinal_number(1) == "1வது"

    def test_ordinal_number_zero(self):
        assert _ordinal_number(0) == "0ஆம்"

    def test_ordinal_number_positive(self):
        assert _ordinal_number(2) == "2ஆம்"
        assert _ordinal_number(10) == "10ஆம்"
        assert _ordinal_number(100) == "100ஆம்"

    def test_ordinal_number_negative(self):
        assert _ordinal_number(-1) == ""
        assert _ordinal_number(-10) == ""

    def test_ordinal_number_large_positive(self):
        assert _ordinal_number(1000) == "1000ஆம்"
        assert _ordinal_number(1000000) == "1000000ஆம்"

    def test_ordinal_number_large_negative(self):
        assert _ordinal_number(-1000) == ""
        assert _ordinal_number(-1000000) == ""

    def test_ordinal_number_edge_case(self):
        assert _ordinal_number(1) == "1வது"
