import pytest
from collections import Mapping

# Assuming the class containing _format_timeframe is named TimeFrameFormatter
class TimeFrameFormatter:
    def __init__(self):
        self.timeframes = {
            'days': '{0} day' if delta == 1 else '{0} days',
            'hours': '{0} hour' if delta == 1 else '{0} hours',
            'minutes': '{0} minute' if delta == 1 else '{0} minutes',
            'seconds': '{0} second' if delta == 1 else '{0} seconds',
            'weeks': {'dual': '{0} weeks', 'plural': '{0} weeks'},
        }

    def _format_timeframe(self, timeframe: str, delta: int) -> str:
        form = self.timeframes[timeframe]
        delta = abs(delta)
        if isinstance(form, Mapping):
            if delta == 2:
                form = form["dual"]
            else:
                form = form["plural"]

        return form.format(delta)

