import pytest

class TestFormatRelative:
    class MockClass:
        past = "{} ago"
        future = "in {}"

        def _format_relative(self, humanized: str, timeframe: str, delta: float) -> str:
            if timeframe == "now":
                return humanized

            direction = self.past if delta < 0 else self.future
            relative_string = direction.format(humanized)

            if timeframe == "seconds":
                relative_string = relative_string.replace(" ", "")

            return relative_string

    def setup_method(self):
        self.mock_instance = self.MockClass()

    def test_format_relative_now(self):
        result = self.mock_instance._format_relative("event", "now", 0)
        assert result == "event"

    def test_format_relative_future(self):
        result = self.mock_instance._format_relative("event", "future", 1)
        assert result == "in event"

    def test_format_relative_past(self):
        result = self.mock_instance._format_relative("event", "past", -1)
        assert result == "event ago"

    def test_format_relative_seconds(self):
        result = self.mock_instance._format_relative("event", "seconds", 1)
        assert result == "inevent"

    def test_format_relative_seconds_past(self):
        result = self.mock_instance._format_relative("event", "seconds", -1)
        assert result == "eventago"

    def test_format_relative_edge_case_zero_delta_future(self):
        result = self.mock_instance._format_relative("event", "future", 0)
        assert result == "in event"

    def test_format_relative_edge_case_zero_delta_past(self):
        result = self.mock_instance._format_relative("event", "past", 0)
        assert result == "event ago"

    def test_format_relative_invalid_timeframe(self):
        with pytest.raises(KeyError):
            self.mock_instance._format_relative("event", "invalid_timeframe", 1)

    def test_format_relative_negative_delta_future(self):
        result = self.mock_instance._format_relative("event", "future", -5)
        assert result == "event ago"

    def test_format_relative_large_positive_delta(self):
        result = self.mock_instance._format_relative("event", "future", 1000)
        assert result == "in event"

    def test_format_relative_large_negative_delta(self):
        result = self.mock_instance._format_relative("event", "past", -1000)
        assert result == "event ago"

