def _ordinal_number(self, n: int) -> str:
    if n > 10 or n == 0:
        return f"{n}তম"
    if n in [1, 5, 7, 8, 9, 10]:
        return f"{n}ম"
    if n in [2, 3]:
        return f"{n}য়"
    if n == 4:
        return f"{n}র্থ"
    if n == 6:
