import pytest
from collections import Mapping

class TestFormatTimeframe:
    class MockTimeFrame:
        timeframes = {
            'days': {
                "2": "{} days",
                "ten": "{} days",
                "higher": "{}+ days"
            },
            'hours': {
                "2": "{} hours",
                "ten": "{} hours",
                "higher": "{}+ hours"
            }
        }

    def _format_timeframe(self, timeframe: str, delta: int) -> str:
        form = self.MockTimeFrame.timeframes[timeframe]
        delta = abs(delta)
        if isinstance(form, Mapping):
            if delta == 2:
                form = form["2"]
            elif delta == 0 or 2 < delta <= 10:
                form = form["ten"]
            else:
                form = form["higher"]

        return form.format(delta)

    def test_format_timeframe_normal_cases(self):
        assert self._format_timeframe('days', 2) == "2 days"
        assert self._format_timeframe('days', 5) == "5 days"
        assert self._format_timeframe('days', 10) == "10 days"
        assert self._format_timeframe('days', 11) == "11+ days"
        assert self._format_timeframe('hours', 2) == "2 hours"
        assert self._format_timeframe('hours', 5) == "5 hours"
        assert self._format_timeframe('hours', 10) == "10 hours"
        assert self._format_timeframe('hours', 11) == "11+ hours"

    def test_format_timeframe_edge_cases(self):
        assert self._format_timeframe('days', 0) == "0 days"
        assert self._format_timeframe('hours', 0) == "0 hours"
        assert self._format_timeframe('days', -2) == "2 days"
        assert self._format_timeframe('hours', -5) == "5 hours"

    def test_format_timeframe_higher_delta(self):
        assert self._format_timeframe('days', 20) == "20+ days"
        assert self._format_timeframe('hours', 25) == "25+ hours"

    def test_format_timeframe_invalid_timeframe(self):
        with pytest.raises(KeyError):
            self._format_timeframe('invalid', 5)

    def test_format_timeframe_non_integer_delta(self):
        with pytest.raises(TypeError):
            self._format_timeframe('days', 'two')
        with pytest.raises(TypeError):
            self._format_timeframe('hours', None)

