def wrapping_func(*args, **kwargs):
    return args, kwargs

# Test cases
def test_decorator_with_normal_case():
    @decorator(1, 2, wrapping_func=wrapping_func)
    def sample_function():
        return 3

    result = sample_function()
    assert result == ((1, 2, 3), {})

def test_decorator_with_args():
    @decorator(10, 20, wrapping_func=wrapping_func)
    def sample_function(a, b):
        return a + b

    result = sample_function(5, 15)
    assert result == ((10, 20, 20), {})

def test_decorator_with_kwargs():
    @decorator(wrapping_func=wrapping_func, key='value')
    def sample_function():
        return 'result'

    result = sample_function()
    assert result == (('result',), {'key': 'value'})

def test_decorator_with_multiple_return_values():
    @decorator(1, 2, wrapping_func=wrapping_func)
    def sample_function():
        return 3, 4

    result = sample_function()
    assert result == ((1, 2, 3), {})

def test_decorator_with_no_return():
    @decorator(1, 2, wrapping_func=wrapping_func)
    def sample_function():
        pass

    result = sample_function()
    assert result == ((1, 2, None), {})

