import pytest

class TestPeek:
    class MockIterator:
        def __init__(self, items):
            self.items = items
            self.index = 0

        def __iter__(self):
            return self

        def __next__(self):
            if self.index < len(self.items):
                item = self.items[self.index]
                self.index += 1
                return item
            raise StopIteration

    class Peekable:
        _marker = object()

        def __init__(self, it):
            self._it = it
            self._cache = []

        def peek(self, default=_marker):
            if not self._cache:
                try:
                    self._cache.append(next(self._it))
                except StopIteration:
                    if default is self._marker:
                        raise
                    return default
            return self._cache[0]

    def test_peek_next_item(self):
        it = self.MockIterator([1, 2, 3])
        peekable = self.Peekable(it)
        assert peekable.peek() == 1

    def test_peek_multiple_calls(self):
        it = self.MockIterator([1, 2, 3])
        peekable = self.Peekable(it)
        assert peekable.peek() == 1
        assert peekable.peek() == 1  # Should still return the same item

    def test_peek_after_next(self):
        it = self.MockIterator([1, 2, 3])
        peekable = self.Peekable(it)
        assert next(peekable._it) == 1
        assert peekable.peek() == 2  # Now it should return the next item

    def test_peek_empty_iterator_with_default(self):
        it = self.MockIterator([])
        peekable = self.Peekable(it)
        assert peekable.peek(default='default') == 'default'

    def test_peek_empty_iterator_without_default(self):
        it = self.MockIterator([])
        peekable = self.Peekable(it)
        with pytest.raises(StopIteration):
            peekable.peek()

    def test_peek_after_exhaustion(self):
        it = self.MockIterator([1])
        peekable = self.Peekable(it)
        assert next(peekable._it) == 1
        assert peekable.peek(default='default') == 'default'  # After exhaustion

    def test_peek_with_custom_default(self):
        it = self.MockIterator([1])
        peekable = self.Peekable(it)
        assert peekable.peek(default='custom_default') == 1
        assert next(peekable._it) == 1
        assert peekable.peek(default='custom_default') == 'custom_default'  # After exhaustion

    def test_peek_with_no_items(self):
        it = self.MockIterator([])
        peekable = self.Peekable(it)
        assert peekable.peek(default='no_items') == 'no_items'
        with pytest.raises(StopIteration):
            peekable.peek()

    def test_peek_with_non_iterable(self):
        with pytest.raises(TypeError):
            peekable = self.Peekable(None)
            peekable.peek()

