    class CustomObject:
        pass

    assert is_scalar(CustomObject()) is True

def test_is_scalar_with_iterators():
    assert is_scalar(iter([1, 2, 3])) is True

def test_is_scalar_with_generator():
    def generator():
        yield 1

    assert is_scalar(generator()) is True

def test_is_scalar_with_empty_iterables():
