import pytest
from unittest.mock import MagicMock, patch
from queue import Queue, Empty
from concurrent.futures import Future, ThreadPoolExecutor

class AbortThread(Exception):
    pass

class TestReader:
    @pytest.fixture
    def setup_reader(self):
        class Reader:
            def __init__(self):
                self._aborted = False
                self._executor = ThreadPoolExecutor()
                self._callback_kwd = 'callback'
                self._func = MagicMock()
                self._wait_seconds = 1
                self._future = Future()

            def _reader(self):
                q = Queue()

                def callback(*args, **kwargs):
                    if self._aborted:
                        raise AbortThread('canceled by user')

                    q.put((args, kwargs))

                self._future = self._executor.submit(
                    self._func, **{self._callback_kwd: callback}
                )

                while True:
                    try:
                        item = q.get(timeout=self._wait_seconds)
                    except Empty:
                        pass
                    else:
                        q.task_done()
                        yield item

                    if self._future.done():
                        break

                remaining = []
                while True:
                    try:
                        item = q.get_nowait()
                    except Empty:
                        break
                    else:
                        q.task_done()
                        remaining.append(item)
                q.join()
                yield from remaining

        return Reader()

    def test_reader_yields_items(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: callback('item1'))
        items = list(reader._reader())
        assert items == [(('item1',), {})]

    def test_reader_aborts(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: callback('item1'))
        reader._aborted = True
        with pytest.raises(AbortThread):
            list(reader._reader())

    def test_reader_no_items(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: None)
        items = list(reader._reader())
        assert items == []

    def test_reader_with_multiple_items(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: [callback('item1'), callback('item2')])
        items = list(reader._reader())
        assert items == [(('item1',), {}), (('item2',), {})]

    def test_reader_waits_for_items(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: callback('item1'))
        items = list(reader._reader())
        assert items == [(('item1',), {})]

    def test_reader_handles_empty_queue(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: None)
        items = list(reader._reader())
        assert items == []

    def test_reader_remaining_items(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: [callback('item1'), callback('item2')])
        items = list(reader._reader())
        assert items == [(('item1',), {}), (('item2',), {})]

    def test_reader_future_done(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: callback('item1'))
        reader._future.set_result(None)
        items = list(reader._reader())
        assert items == [(('item1',), {})]

    def test_reader_future_not_done(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: callback('item1'))
        reader._future.set_running_or_notify_cancel()
        items = list(reader._reader())
        assert items == [(('item1',), {})]

    def test_reader_timeout(self, setup_reader):
        reader = setup_reader
        reader._func = MagicMock(side_effect=lambda callback: None)
        reader._wait_seconds = 0.1
        items = list(reader._reader())
        assert items == []
